"""RouteResolver — Router 분기 결정과 서브그래프 제외."""

from __future__ import annotations

import logging
from typing import Any

from mantis.models.node import NodeInfo, PortInfo, EdgeInfo

logger = logging.getLogger(__name__)


class RouteResolver:
    """Router 노드의 분기 결정과 서브그래프 제외를 담당."""

    def __init__(self, edges: list[EdgeInfo]):
        self._edges = edges

    def evaluate(
        self,
        node: NodeInfo,
        result: dict[str, Any],
        excluded: set[str],
    ) -> str | None:
        """라우팅 결과를 평가하고 excluded를 갱신.

        Returns: 선택된 포트 ID (또는 None).
        """
        if node.function_id != "router":
            return None

        routing_criteria = node.parameters.get("routing_criteria", "")
        route_key = self._get_route_key(result, routing_criteria)

        # output 포트 매칭
        selected_port = None
        for port in node.outputs:
            if self._is_port_match(port.id, route_key):
                selected_port = port.id
                break

        # 폴백: default 포트 또는 첫 번째 포트
        if selected_port is None:
            for port in node.outputs:
                if port.id.lower() == "default":
                    selected_port = port.id
                    break
            if selected_port is None and node.outputs:
                selected_port = node.outputs[0].id

        # 미선택 포트의 하위 서브그래프를 excluded에 추가
        for port in node.outputs:
            if port.id != selected_port:
                targets = [
                    e.target_node for e in self._edges
                    if e.source_node == node.id and e.source_port == port.id
                ]
                for target in targets:
                    self._exclude_descendants(target, excluded)

        logger.info("RouteResolver: node=%s, key=%s, selected=%s", node.id, route_key, selected_port)
        return selected_port

    def evaluate_dependency(
        self,
        node: NodeInfo,
    ) -> tuple[set[str], set[str]]:
        """output port dependency 평가.

        Returns: (active_port_ids, inactive_port_ids)
        """
        active = set()
        inactive = set()

        for port in node.outputs:
            if port.dependency is None:
                active.add(port.id)
                continue

            param_value = node.parameters.get(port.dependency)
            if port.dependency_value is not None:
                if self._compare_values(param_value, port.dependency_value):
                    active.add(port.id)
                else:
                    inactive.add(port.id)
            else:
                if param_value:
                    active.add(port.id)
                else:
                    inactive.add(port.id)

        return active, inactive

    def _exclude_descendants(self, node_id: str, excluded: set[str]) -> None:
        """DFS로 하위 노드를 전부 excluded에 추가."""
        if node_id in excluded:
            return
        excluded.add(node_id)
        for edge in self._edges:
            if edge.source_node == node_id:
                self._exclude_descendants(edge.target_node, excluded)

    @staticmethod
    def _get_route_key(data: dict[str, Any], criteria: str) -> str:
        if isinstance(data, dict):
            value = data.get(criteria, data.get("result", ""))
        else:
            value = data
        if isinstance(value, bool):
            return "true" if value else "false"
        if value is None:
            return ""
        return str(value).lower().strip()

    @staticmethod
    def _is_port_match(port_id: str, route_key: str) -> bool:
        pid = port_id.lower().strip()
        rk = route_key.lower().strip()
        if pid == rk:
            return True
        bool_map = {"true": {"yes", "1", "true"}, "false": {"no", "0", "false"}}
        for canonical, variants in bool_map.items():
            if pid in variants and rk in variants:
                return True
        return False

    @staticmethod
    def _compare_values(actual: Any, expected: Any) -> bool:
        if isinstance(expected, bool) or isinstance(actual, bool):
            return bool(actual) == bool(expected)
        return str(actual).lower().strip() == str(expected).lower().strip()
